          font-size: 14px;
          color: var(--text-muted);
        }

        .header-actions {
          display: flex;
          gap: 10px;
        }

        .btn-secondary {
          background: var(--bg-2);
          border: 1px solid var(--border);
          color: var(--text);
        }

        .btn-secondary:hover {
          border-color: var(--accent);
          color: var(--accent);
        }

        /* Dropdown */
        .dropdown-container {
          position: relative;
        }

        .dropdown-menu {
          position: absolute;
          top: 100%;
          right: 0;
          margin-top: 6px;
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 10px;
          box-shadow: 0 10px 40px rgba(0, 0, 0, 0.12);
          min-width: 200px;
          z-index: 100;
          animation: fadeIn 0.15s ease;
          overflow: hidden;
        }

        .dropdown-menu button, .dropdown-item {
          display: flex;
          align-items: center;
          gap: 10px;
          width: 100%;
          padding: 12px 16px;
          border: none;
          background: none;
          color: var(--text);
          font-size: 13.5px;
          cursor: pointer;
          text-align: left;
          transition: background 0.15s;
        }

        .dropdown-menu button:hover, .dropdown-item:hover {
          background: var(--bg-3);
        }

        .dropdown-divider {
          height: 1px;
          background: var(--border);
          margin: 4px 0;
        }

        /* Stats row */
        .stats-row {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 16px;
          margin-bottom: 24px;
        }

