          border-color: var(--accent);
        }

        .quantity-range {
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .quantity-range input {
          width: 80px !important;
        }

        .quantity-range span {
          color: var(--text-muted);
        }

        /* View toggle */
        .view-toggle {
          display: flex;
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 8px;
          overflow: hidden;
        }

        .view-btn {
          padding: 8px 12px;
          border: none;
          background: none;
          color: var(--text-muted);
          cursor: pointer;
          transition: all 0.15s;
        }

        .view-btn:hover {
          color: var(--text);
        }

        .view-btn.active {
          background: var(--accent);
          color: white;
        }

        /* Loading */
        .loading-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          padding: 80px 20px;
        }

        .loading-container p {
          margin-top: 16px;
          color: var(--text-muted);
          font-size: 14px;
        }

        /* Empty state */
        .empty-state-container {
          max-width: 480px;
          margin: 60px auto;
          text-align: center;
          padding: 40px;
          background: var(--bg-2);
          border-radius: 16px;
          border: 1px solid var(--border);
        }

        .empty-illustration {
          position: relative;
          width: 120px;
          height: 120px;
          margin: 0 auto 24px;
        }

        .empty-icon-wrapper {
          width: 100%;
          height: 100%;
          background: linear-gradient(135deg, var(--bg-3), var(--bg-2));
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          color: var(--text-muted);
          border: 2px solid var(--border);
        }

        .empty-pulse {
          position: absolute;
          inset: -10px;
          border-radius: 50%;
          border: 2px dashed var(--border);
          animation: spin 20s linear infinite;
        }

        @keyframes spin {
          to { transform: rotate(360deg); }
        }

        .empty-state-container h2 {
          font-size: 20px;
          font-weight: 600;
          margin-bottom: 8px;
          color: var(--text);
        }

        .empty-state-container p {
          color: var(--text-muted);
          font-size: 14px;
          margin-bottom: 24px;
          line-height: 1.5;
        }

        .empty-tips {
          display: flex;
          justify-content: center;
          gap: 24px;
          margin-top: 32px;
          padding-top: 24px;
          border-top: 1px solid var(--border);
        }

        .tip {
          display: flex;
          align-items: center;
          gap: 8px;
          font-size: 12px;
          color: var(--text-muted);
        }

        .tip svg {
          color: var(--accent);
        }

        /* No results */
        .no-results {
          text-align: center;
          padding: 60px 20px;
          color: var(--text-muted);
        }

        .no-results svg {
          margin-bottom: 16px;
          opacity: 0.4;
        }

        .no-results h3 {
          font-size: 18px;
          font-weight: 600;
          color: var(--text);
          margin-bottom: 8px;
        }

        .no-results p {
          font-size: 14px;
          margin-bottom: 20px;
        }

        /* Table */
        .table-container {
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 12px;
          overflow: hidden;
        }

        .modern-table {
          width: 100%;
          border-collapse: collapse;
        }

        .modern-table thead {
          background: var(--bg-3);
        }

        .modern-table th {
          padding: 14px 16px;
          font-size: 11px;
          font-weight: 600;
          text-transform: uppercase;
          letter-spacing: 0.8px;
          color: var(--text-muted);
          text-align: left;
          white-space: nowrap;
        }

        .modern-table th[style*="cursor"] {
          cursor: pointer;
        }

        .modern-table th span {
          margin-left: 6px;
          opacity: 0.6;
        }

        .modern-table td {
          padding: 14px 16px;
          font-size: 13.5px;
          border-top: 1px solid var(--border);
          vertical-align: middle;
        }

        .table-container tbody tr {
          transition: background 0.15s;
          animation: fadeInRow 0.3s ease forwards;
          opacity: 0;
        }

        @keyframes fadeInRow {
          to { opacity: 1; }
        }

        .table-container tbody tr:hover {
          background: rgba(99, 102, 241, 0.04);
        }

        .quantity-cell {
          min-width: 140px;
        }

        .quantity-bar-wrapper {
          margin-bottom: 8px;
        }

        .quantity-bar {
          height: 6px;
          background: var(--bg-3);
          border-radius: 3px;
          overflow: hidden;
        }

        .quantity-bar-fill {
          height: 100%;
          border-radius: 3px;
          transition: width 0.3s ease;
        }

        .quantity-info {
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .quantity-value {
          font-weight: 600;
          font-family: var(--mono);
        }

        .status-badge {
          display: inline-flex;
          align-items: center;
          gap: 4px;
          padding: 4px 8px;
          border-radius: 6px;
          font-size: 11px;
          font-weight: 600;
        }

        .row-actions {
          display: flex;
          gap: 6px;
        }

        .action-btn {
          width: 32px;
          height: 32px;
          border: none;
          border-radius: 6px;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: all 0.15s;
          background: transparent;
          color: var(--text-muted);
        }

        .action-btn:hover {
          background: var(--accent-light);
          color: var(--accent);
        }

        .action-btn.delete:hover {
          background: rgba(239, 68, 68, 0.1);
          color: #ef4444;
        }

        /* Pagination */
        .pagination {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 16px;
          border-top: 1px solid var(--border);
          flex-wrap: wrap;
          gap: 12px;
        }

        .pagination-info {
          font-size: 13px;
          color: var(--text-muted);
        }

        .pagination-controls {
          display: flex;
          gap: 6px;
        }

        .page-btn {
          padding: 8px 14px;
          border: 1px solid var(--border);
          border-radius: 6px;
          background: var(--bg-2);
          color: var(--text);
          font-size: 13px;
          cursor: pointer;
          transition: all 0.15s;
        }

        .page-btn:hover:not(:disabled) {
          border-color: var(--accent);
          color: var(--accent);
        }

        .page-btn.active {
          background: var(--accent);
          border-color: var(--accent);
          color: white;
        }

        .page-btn:disabled {
          opacity: 0.5;
          cursor: not-allowed;
        }

        /* Cards view */
        .cards-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
          gap: 16px;
        }

        .stock-card {
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 12px;
          padding: 16px;
          transition: all 0.2s;
          animation: fadeInRow 0.3s ease forwards;
          opacity: 0;
        }

        .stock-card:hover {
          border-color: var(--accent);
          box-shadow: 0 8px 24px rgba(0, 0, 0, 0.08);
        }

        .card-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 16px;
        }

        .card-product {
          display: flex;
          gap: 12px;
        }

        .card-product svg {
          color: var(--text-muted);
        }

        .card-product h4 {
          font-size: 14px;
          font-weight: 600;
          color: var(--text);
          margin-bottom: 2px;
        }

        .card-product span {
          font-size: 12px;
          color: var(--text-muted);
        }

        .card-quantity {
          display: flex;
          align-items: baseline;
          gap: 8px;
          margin-bottom: 16px;
        }

        .card-quantity .qty {
          font-size: 28px;
          font-weight: 700;
          font-family: var(--mono);
          color: var(--text);
        }

        .card-quantity .unit {
          font-size: 12px;
          color: var(--text-muted);
        }

        .card-footer {
          display: flex;
          gap: 8px;
          padding-top: 12px;
          border-top: 1px solid var(--border);
        }

        /* Stock details modal */
        .stock-details {
          padding: 8px 0;
        }

        .detail-row {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 12px 0;
          border-bottom: 1px solid var(--border);
        }

        .detail-row:last-of-type {
          border-bottom: none;
        }

        .detail-row label {
          font-size: 13px;
          color: var(--text-muted);
        }

        .detail-row span {
          font-size: 14px;
          font-weight: 500;
          color: var(--text);
        }

        .detail-row .qty {
          font-family: var(--mono);
          font-weight: 600;
        }

        .detail-actions {
          display: flex;
          gap: 10px;
          margin-top: 20px;
        }

        /* Responsive */
        @media (max-width: 1024px) {
          .stats-row {
            grid-template-columns: repeat(2, 1fr);
          }

          .filters-section {
            flex-direction: column;
            align-items: stretch;
          }

          .search-filter {
            min-width: 100%;
          }

          .view-toggle {
            align-self: flex-end;
          }

          .filters-panel {
            left: 0;
            right: 0;
            min-width: auto;
          }
        }

        @media (max-width: 768px) {
          .page-header-modern {
            flex-direction: column;
          }

          .header-actions {
            width: 100%;
          }

          .header-actions .btn {
            flex: 1;
            justify-content: center;
          }

          .stats-row {
            grid-template-columns: 1fr;
          }

          .table-container {
            overflow-x: auto;
          }

          .modern-table {
            min-width: 600px;
          }

          .pagination {
            flex-direction: column;
            text-align: center;
          }

          .pagination-controls {
            flex-wrap: wrap;
            justify-content: center;
          }
        }

        /* Dark mode */
        .dark-mode .stock-card:hover,
        .dark-mode .table-container tbody tr:hover {
          background: rgba(255, 255, 255, 0.02);
        }
      `}</style>
    </div>
  );
}
